import { useMediaQuery } from 'react-responsive';
import AliceCarousel from 'react-alice-carousel';
import 'react-alice-carousel/lib/alice-carousel.css';
import { forwardRef, useRef } from 'react';

const handleDragStart = (e) => e.preventDefault();
const items = [
  <img src="img/services/pick_a_restaurant.svg" onDragStart={handleDragStart} alt="" />,
  <img src="img/services/skip_the_messaging.svg" onDragStart={handleDragStart} alt="" />,
  <img src="img/services/go_on_a_date.svg" onDragStart={handleDragStart} alt="" />,
];

const Carousel = forwardRef((props, ref) => {
  return (
    <AliceCarousel
      ref={ref}
      mouseTracking
      autoPlay={true}
      autoPlayInterval={5000}
      buttonsDisabled={true}
      infinite={true}
      items={items} />
  )
})

export const Services = (props) => {
  const isMobile = useMediaQuery({ maxWidth: 1000 });
  const carouselRef = useRef(null);

  return (
    <div id='services' className='text-center'>
      <div className='container'>
        {isMobile ? (
          <div className='row'>
            <div className='col-xs-1'>
              <button className="custom-carousel-navigation-button" onClick={
                carouselRef.current ? carouselRef.current.slidePrev : () => {}
                }>
                <i className="fa fa-angle-left" />
              </button>
            </div>
            <div className='col-xs-10'>
              <Carousel ref={carouselRef} />
            </div>
            <div className='col-xs-1'>
              <button className="custom-carousel-navigation-button" onClick={
                carouselRef.current ? carouselRef.current.slideNext : () => {}
                }>
                <i className="fa fa-angle-right" />
              </button>
            </div>
          </div>
        ) : (
          <div className='row-fluid'>
            {props.data
              ? props.data.map((d, i) => (
                  <div key={`${d.name}-${i}`} className='col-md-4'>
                    {' '}
                    <div>
                      <img src={d.img} alt='' />{' '}
                    </div>
                    <div className='service-desc'>
                      <h3>{d.name}</h3>
                      <p>{d.text}</p>
                    </div>
                  </div>
                ))
              : 'loading'}
          </div>
        )}
      </div>
    </div>
  )
}
